def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 2, -2):
                for b in range(1, a + 4):
                    val = ((ratio - a) ** 7) / (a * b * 1.2 + 2)
                    priority += val * np.sin(ratio * b / (a + 2)) * 1.5
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 1.7 - np.sqrt(ratio) * 4
        elif 5 < ratio <= 8:
            for p in range(2, int(np.ceil(ratio)) + 4, 2):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * 0.9) / (q + 1)
                    priority += np.tanh(term) * 1.5
            priority += np.log1p(ratio) * 12 - np.tanh(ratio - 5) * 3
        elif 3 <= ratio <= 5:
            s = 0
            for r in range(2, 14):
                s += ((ratio - 3) ** r) / (r * 2.2) * np.sin(r * ratio * 0.8)
            priority = (s * np.sin(6 * ratio)) - np.log(ratio) * 7 + np.tanh(3 * (5 - ratio)) * 2
        elif 2 <= ratio < 3:
            s = 0
            for n in range(1, 13):
                s += ((3 - ratio) ** n) / (n ** 2 + 1.2)
            if bin_cap < item * 1.3:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-1.8 / (ratio + 0.07))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 1.1) * ((ratio - 1.9) ** m) / m
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 18):
                s += ((2 - ratio) ** n) / (n * 5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.8
            else:
                priority /= (np.sqrt(bin_cap + 2.3) + 3)
            for j in range(1, 8):
                priority += ((2 - ratio) ** j) * np.sin(j * item * 1.6) * 0.9
        elif 0.5 <= ratio < 1:
            s = 0
            for k in range(1, 14):
                s += ((1 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 2.3)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.8) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((1 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.4)
        elif 0.2 <= ratio < 0.5:
            s = 0
            for t in range(1, 11):
                s += ((0.5 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 2.8
            else:
                priority /= 2.8
            if bin_cap < item * 0.2:
                priority += np.exp(-ratio * item) * 6
            else:
                priority -= np.log1p(bin_cap * ratio) * 3.5
            for u in range(1, 10):
                priority += ((0.5 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.9)
        else:
            s = 0
            for v in range(1, 13):
                s += ((0.2 - ratio) ** v) / (v * 9) * np.sin(v * item * 1.0)
            priority = s + 4 / (bin_cap + 6)
            if int(item * 0.8) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for w in range(1, 12):
                priority += ((0.2 - ratio) ** w) / (w * 10) * np.cos(item * w * 0.7)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx * 2)) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx * 2)) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if priority < -50:
            priority = -50 + np.tanh(priority + 50) * 10
        elif priority > 50:
            priority = 50 + np.tanh(priority - 50) * 10
        priorities[i] = priority
    return priorities
